INSERT INTO `categories` VALUES (4,'মসজিদের নিয়োগ বিজ্ঞপ্তি','mosque-jobs','এখানে সারা বাংলাদেশের মসজিদের নিয়োগ প্রকাশ করা হয়। যেমন, ইমাম নিয়োগ, খতিব নিয়োগ, মুয়াজ্জিন নিয়োগ, ইমাম ও খতিব নিয়োগ, ইমাম ও মুয়াজ্জিন নিয়োগ, মোয়াজ্জিন নিয়োগ, মসজিদের খাদেম নিয়োগ ইত্যাদি মসজিদের সকল ধরনের নিয়োগ বিজ্ঞপ্তি দেওয়া হয়। মসজিদের খেদমত সেন্টার, খেদমত সেন্টার, মসজিদ মাদ্রাসার খেদমত সেন্টার।','মসজিদের নিয়োগ বিজ্ঞপ্তি | মসজিদ-মাদ্রাসার খেদমত সেন্টার','সারা বাংলাদেশের মসজিদের ইমাম, খতিব, মুয়াজ্জিন ও খাদেম নিয়োগ বিজ্ঞপ্তি। মসজিদের খেদমত সেন্টার।',0),(5,'পুরুষ মাদ্রাসার নিয়োগ','male-madrasa-jobs','এখানে সারা বাংলাদেশের পুরুষ মাদ্রাসার নিয়োগ প্রকাশ করা হয়। যেমন, মাদ্রাসার শিক্ষক নিয়োগ, হাফেজ নিয়োগ, আলেম নিয়োগ, নূরানী শিক্ষক নিয়োগ, হিফজ শিক্ষক নিয়োগ, নাজেরা শিক্ষক নিয়োগ, কিতাবখানার শিক্ষক নিয়োগ, মাদ্রাসার খাদেম নিয়োগ, মাদ্রাসার দারোয়ান নিয়োগ, মোহতামিম নিয়োগ, মাদ্রাসার বাবুর্চি নিয়োগ ইত্যাদি মাদ্রাসার সকল নিয়োগ বিজ্ঞপ্তি দেওয়া হয়। মাদ্রাসার খেদমত সেন্টার, খেদমত সেন্টার, মসজিদ মাদ্রাসার খেদমত সেন্টার।','পুরুষ মাদ্রাসার নিয়োগ | মসজিদ-মাদ্রাসার খেদমত সেন্টার','সারা বাংলাদেশের পুরুষ মাদ্রাসার শিক্ষক, হাফেজ, আলেম নিয়োগ বিজ্ঞপ্তি। মাদ্রাসার খেদমত সেন্টার।',0),(6,'মহিলা মাদ্রাসার নিয়োগ','female-madrasa-jobs','এখানে সারা বাংলাদেশের মহিলা মাদ্রাসার নিয়োগ প্রকাশ করা হয়। যেমন, মাদ্রাসার শিক্ষিকা নিয়োগ, হাফেজা নিয়োগ, আলোমা নিয়োগ, নূরানী শিক্ষিকা নিয়োগ, হেফজ শিক্ষিকা নিয়োগ, নাজেরা শিক্ষিকা নিয়োগ, কিতাবখানার শিক্ষিকা নিয়োগ, মাদ্রাসার খাদেমা নিয়োগ, মহিলা বাবুর্চি নিয়োগ, মুহতামিমা নিয়োগ ইত্যাদি মহিলা মাদ্রাসার সকল নিয়োগ বিজ্ঞপ্তি দেওয়া হয়। মাদ্রাসার খেদমত সেন্টার, খেদমত সেন্টার, মসজিদ মাদ্রাসার খেদমত সেন্টার।','মহিলা মাদ্রাসার নিয়োগ | মসজিদ-মাদ্রাসার খেদমত সেন্টার','সারা বাংলাদেশের মহিলা মাদ্রাসার শিক্ষিকা, হাফেজা নিয়োগ বিজ্ঞপ্তি। মাদ্রাসার খেদমত সেন্টার।',0);
