INSERT INTO `posts` VALUES ('p_6a2a027f34a942.38625868','হিফজ বিভাগে একজন দক্ষ ও অভিজ্ঞ হাফেজ প্রয়োজন। শর্ত মাদরাসার মসজিদে খতমে তারাবি পড়ানোর যোগ্যতা থাকতে হবে। ঠিকানাঃ রূপগঞ্জ, নারায়ণগঞ্জ। \nমুহতামিমঃ ০১৯০৬৯৮৯০৪৮',NULL,'Admin','[]','','',1781138047000,'11 Jun 2026',0,0,'',0,NULL,'খেদমত-পোস্ট-3c587f','mosque-jobs',NULL,NULL,NULL,'active',NULL,NULL),('p_6a2a02f1b6b847.10155179','আলেমা শিক্ষিকা নিয়োগ দেওয়া হবে।\nআশুলিয়া সাভার ঢাকা \n01624705930',NULL,'Admin','[]','','',1781138161000,'11 Jun 2026',0,0,'',0,NULL,'খেদমত-পোস্ট-d2161c','male-madrasa-jobs',NULL,NULL,NULL,'active',NULL,NULL),('p_6a2a0309667ab2.49876834','নামাজ পড়ানোর জন্য ইমাম লাগবে হাফেজ বা মাওলানা পাশাপাশি দোকানে কাজ করতে হবে স্যালারি ১৮৫০০৳ যোগাযোগ হোয়াটসঅ্যাপ বা ইমুতে 01840668737',NULL,'Admin','[]','','',1781138185000,'11 Jun 2026',0,0,'',0,NULL,'খেদমত-পোস্ট-912da7','female-madrasa-jobs',NULL,NULL,NULL,'active',NULL,NULL),('p_6a2a03944a3780.91470574','📖 নূরানী উস্তাদ আবশ্যক 📖\n\nকুমিল্লা জেলার অন্তর্গত তিতাস উপজেলাধীন মনোরম ও সুশৃঙ্খল গ্রামীণ পরিবেশে অবস্থিত একটি কওমী মাদরাসায় ছাত্র গড়ায় দক্ষ, দায়িত্বশীল ও আন্তরিক নূরানী প্রশিক্ষণপ্রাপ্ত উস্তাদ আবশ্যক।\n\n✅ আবশ্যক যোগ্যতা ✅\n🔹 চট্টগ্রাম বোর্ডের নূরানী প্রশিক্ষণপ্রাপ্ত হতে হবে।\n🔹 মাওলানা / হাফেজ হতে হবে। ( উভয় যোগ্যতা থাকলে অগ্রাধিকার)\n🔹 আবাসিক থাকতে হবে।\n\n🌟 অতিরিক্ত যোগ্যতা (অগ্রাধিকার) 🌟\n🔸 কয়েক বছরের অভিজ্ঞতা থাকলে ভালো হয়।\n🔸 কুমিল্লা জেলা ও তৎসংলগ্ন এলাকার হলে ভালো হয়।\n🔸 বিবাহিত হলে ভালো হয়।\n\n🎁 সুযোগ-সুবিধা 🎁\n💠 মাসিক সম্মানী ১০,০০০/- টাকা প্রদান করা হবে ইনশাআল্লাহ।\n💠 প্রতি মাসের ১–১০ তারিখের মধ্যে হাদিয়া প্রদান করা হবে ইনশাআল্লাহ। (আশাবাদী ১/২ তারিখেই প্রদান করা সম্ভব হবে ইনশাআল্লাহ)\n💠 দুই ঈদে অল্পকিছু বোনাস থাকবে ইনশাআল্লাহ।\n💠 পরীক্ষার ফি (খরচ ব্যতীত) সম্পূর্ণ সমানহারে বণ্টন হবে ইনশাআল্লাহ।\n💠 মাদরাসা কর্তৃক নির্ধারিত ছুটি ব্যতীত বাৎসরিক সর্বমোট ২০ দিন ঐচ্ছিক ছুটি থাকবে ইনশাআল্লাহ।\n\n👤 যোগাযোগ 👤\nমাওলানা মুফতি শরিফুল ইসলাম আরাফাত\nমুহতামিম, বারকাউনিয়া নওয়াবুল উলুম মাদরাসা, তিতাস, কুমিল্লা।\n📳 01715-437175',NULL,'Admin','[]','','